		assertThat(LmdbNativeSpecialization.filterKernel(cacheOwner, 3, readMask, 1L)).isNull();
		NativeBatchFilterKernel kernel = LmdbNativeSpecialization.awaitFilterKernel(cacheOwner, 3, readMask, 5,
				TimeUnit.SECONDS);
